"""APS Local DB — Plan Evaluation models."""

from datetime import datetime
from typing import Optional
from sqlalchemy import String, Integer, Boolean, Index, DateTime, Text
from sqlalchemy.dialects.postgresql import JSONB
from sqlalchemy.orm import Mapped, mapped_column


from app.db.database import Base


class PlanEvaluationAction(Base):
    """Recommended actions generated by LLM + feasibility binding.

    action_type values: CHANGE_DELIVERY_DATE | APPLY_OVERTIME | CHANGE_PRIORITY |
    CREATE_PURCHASE_REQUEST | SUBSTITUTE_MATERIAL | REALLOCATE_INVENTORY |
    SHIFT_SCHEDULE | LINE_BALANCE

    Idempotency: (impacted_id, action_type, param_hash) is unique — prevents
    duplicate actions for the same risk with the same normalized parameters.
    """
    __tablename__ = "plan_evaluation_action"
    __table_args__ = (
        Index(
            "uq_action_impacted_type_hash",
            "impacted_id", "action_type", "param_hash",
            unique=True,
        ),
        {"schema": "aps_result"},
    )

    id: Mapped[int] = mapped_column(Integer, primary_key=True, autoincrement=True)
    scenario_id: Mapped[str] = mapped_column(String(50), index=True, nullable=False)
    # Optional: link to a specific plan_order if action is order-specific
    plan_id: Mapped[Optional[str]] = mapped_column(String(50), index=True)
    # Link to the risk that triggered this action card generation
    impacted_id: Mapped[Optional[str]] = mapped_column(
        String(50),
        index=True, nullable=True,
    )

    action_type: Mapped[str] = mapped_column(String(50), index=True, nullable=False)
    enabled: Mapped[bool] = mapped_column(Boolean, default=False, index=True, nullable=False)
    reason: Mapped[Optional[str]] = mapped_column(String(500), nullable=True)

    # UI display fields
    title: Mapped[Optional[str]] = mapped_column(String(255), nullable=True)
    description: Mapped[Optional[str]] = mapped_column(Text, nullable=True)

    # Structured action parameters — validated by feasibility checker
    parameters: Mapped[Optional[dict]] = mapped_column(JSONB, nullable=True)
    # SHA-256 of normalized JSON(parameters) — used in unique constraint
    param_hash: Mapped[Optional[str]] = mapped_column(String(64), nullable=True)

    # Idempotency: set when action is applied via execute API
    executed_at: Mapped[Optional[datetime]] = mapped_column(DateTime(timezone=True), nullable=True)
